import React, { useState } from "react";

function Message({ msg }) {

  const [showOptions, setShowOptions] = useState(false);

  // USER MESSAGE
  if (msg.type === "user") {
    return <div className="user-msg">{msg.text}</div>;
  }

  // LOADING
  if (msg.loading) {
    return (
      <div className="ai-msg">
        <div className="pipeline">
          <span>Query → Router → Retriever → Reasoning → Formatter</span>
        </div>
        <div className="thinking">Processing agents...</div>
      </div>
    );
  }

  // ERROR
  if (msg.text && !msg.answer) {
    return <div className="ai-msg">{msg.text}</div>;
  }

  const answerPoints = msg.answer?.split("•").filter(p => p.trim());

  // COPY HANDLERS
  const copyFull = () => {
    const fullText = `
Auto Corrected Query:
${msg.corrected_query}

Final Answer:
${answerPoints.join("\n")}
    `;
    navigator.clipboard.writeText(fullText);
    setShowOptions(false);
  };

  const copyAnswerOnly = () => {
    const answerText = answerPoints.join("\n");
    navigator.clipboard.writeText(answerText);
    setShowOptions(false);
  };

  return (
    <div className="ai-msg">

      {/* COPY ICON */}
      <div className="copy-container">
        <button
          className="copy-btn"
          onClick={() => setShowOptions(!showOptions)}
          title="Copy"
        >
          📋
        </button>

        {showOptions && (
          <div className="copy-dropdown">
            <div onClick={copyFull}>Copy full response</div>
            <div onClick={copyAnswerOnly}>Copy only answer</div>
          </div>
        )}
      </div>

      {/* AUTO CORRECT */}
      <div className="section-card">
        <h4>Auto-Corrected Query</h4>
        <p>{msg.corrected_query}</p>
      </div>

      {/* FINAL ANSWER */}
      <div className="section-card">
        <h4>Final Answer</h4>
        <ul>
          {answerPoints.map((p, i) => (
            <li key={i}>{p}</li>
          ))}
        </ul>
      </div>

      {/* DOCUMENTS */}
      <div className="section-card">
        <h4>Top Retrieved Documents</h4>
        <ul>
          {msg.explanations?.map((doc, i) => (
            <li key={i}>
              <strong>{doc.source}</strong><br />
              Score: {doc.score}<br />
              Reason: {doc.reason}
            </li>
          ))}
        </ul>
      </div>

      {/* METRICS */}
      <div className="section-card">
        <h4>RAG Metrics</h4>
        <ul>
          {msg.metrics &&
            Object.entries(msg.metrics).map(([key, val], i) => (
              <li key={i}>{key}: {val}</li>
            ))}
          <li><strong>Response Time:</strong> {msg.response_time}s</li>
        </ul>
      </div>

    </div>
  );
}

export default Message;
